package com.taskmind.backend.integration.infrastructure.persistence.jpa;
import com.taskmind.backend.integration.domain.model.*; import com.taskmind.backend.integration.domain.repository.IntegrationConnectionRepository; import java.sql.*; import java.time.Instant; import java.util.*; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.stereotype.Repository;
@Repository public class JdbcIntegrationConnectionRepository implements IntegrationConnectionRepository { private final JdbcTemplate jdbc; public JdbcIntegrationConnectionRepository(JdbcTemplate jdbc){this.jdbc=jdbc;} public IntegrationConnection save(IntegrationConnection c){jdbc.update("MERGE INTO integration_connections (id,version,provider,account_name,base_url,account_external_id,owner_user_id,encrypted_access_token,encrypted_refresh_token,token_expires_at,scopes,status,created_at,updated_at) KEY(id) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)",c.id(),0,c.provider().name(),c.accountName(),c.baseUrl(),c.accountExternalId(),c.ownerUserId(),c.encryptedAccessToken(),c.encryptedRefreshToken(),c.tokenExpiresAt(),c.scopes(),c.status(),c.createdAt(),c.updatedAt());return c;} public List<IntegrationConnection> findByOwnerUserId(UUID ownerUserId){return jdbc.query("SELECT * FROM integration_connections WHERE owner_user_id=? ORDER BY created_at",this::map,ownerUserId);} public Optional<IntegrationConnection> findById(UUID id){return jdbc.query("SELECT * FROM integration_connections WHERE id=?",this::map,id).stream().findFirst();} private IntegrationConnection map(ResultSet rs,int row)throws SQLException{return new IntegrationConnection((UUID)rs.getObject("id"),rs.getLong("version"),IntegrationProvider.valueOf(rs.getString("provider")),rs.getString("account_name"),rs.getString("base_url"),rs.getString("account_external_id"),(UUID)rs.getObject("owner_user_id"),rs.getString("encrypted_access_token"),rs.getString("encrypted_refresh_token"),i(rs,"token_expires_at"),rs.getString("scopes"),rs.getString("status"),i(rs,"created_at"),i(rs,"updated_at"));} private Instant i(ResultSet rs,String c)throws SQLException{java.sql.Timestamp ts=rs.getTimestamp(c);return ts==null?null:ts.toInstant();}}
